213 static bool canWidenLoad(LoadInst *Load, const TargetTransformInfo &TTI) {
214   // Do not widen load if atomic/volatile or under asan/hwasan/memtag/tsan.
215   // The widened load may load data from dirty regions or create data races
216   // non-existent in the source.
217   if (!Load || !Load->isSimple() || !Load->hasOneUse() ||
218       Load->getFunction()->hasFnAttribute(Attribute::SanitizeMemTag) ||
219       mustSuppressSpeculation(*Load))
220     return false;
221 
222   // We are potentially transforming byte-sized (8-bit) memory accesses, so make
223   // sure we have all of our type-based constraints in place for this target.
224   Type *ScalarTy = Load->getType()->getScalarType();
225   uint64_t ScalarSize = ScalarTy->getPrimitiveSizeInBits();
226   unsigned MinVectorSize = TTI.getMinVectorRegisterBitWidth();
227   if (!ScalarSize || !MinVectorSize || MinVectorSize % ScalarSize != 0 ||
228       ScalarSize % 8 != 0)
229     return false;
230 
231   return true;
232 }
