234 bool VectorCombine::vectorizeLoadInsert(Instruction &I) {
235   // Match insert into fixed vector of scalar value.
236   // TODO: Handle non-zero insert index.
237   Value *Scalar;
238   if (!match(&I,
239              m_InsertElt(m_Poison(), m_OneUse(m_Value(Scalar)), m_ZeroInt())))
240     return false;
241 
242   // Optionally match an extract from another vector.
243   Value *X;
244   bool HasExtract = match(Scalar, m_ExtractElt(m_Value(X), m_ZeroInt()));
245   if (!HasExtract)
246     X = Scalar;
247 
248   auto *Load = dyn_cast<LoadInst>(X);
249   if (!canWidenLoad(Load, TTI))
250     return false;
251 
252   Type *ScalarTy = Scalar->getType();
253   uint64_t ScalarSize = ScalarTy->getPrimitiveSizeInBits();
254   unsigned MinVectorSize = TTI.getMinVectorRegisterBitWidth();
255 
256   // Check safety of replacing the scalar load with a larger vector load.
257   // We use minimal alignment (maximum flexibility) because we only care about
258   // the dereferenceable region. When calculating cost and creating a new op,
259   // we may use a larger value based on alignment attributes.
260   Value *SrcPtr = Load->getPointerOperand()->stripPointerCasts();
261   assert(isa<PointerType>(SrcPtr->getType()) && "Expected a pointer type");
262 
263   unsigned MinVecNumElts = MinVectorSize / ScalarSize;
264   auto *MinVecTy = VectorType::get(ScalarTy, MinVecNumElts, false);
265   unsigned OffsetEltIndex = 0;
266   Align Alignment = Load->getAlign();
267   if (!isSafeToLoadUnconditionally(SrcPtr, MinVecTy, Align(1), *DL, Load, &AC,
268                                    &DT)) {
269     // It is not safe to load directly from the pointer, but we can still peek
270     // through gep offsets and check if it safe to load from a base address with
271     // updated alignment. If it is, we can shuffle the element(s) into place
272     // after loading.
273     unsigned OffsetBitWidth = DL->getIndexTypeSizeInBits(SrcPtr->getType());
274     APInt Offset(OffsetBitWidth, 0);
275     SrcPtr = SrcPtr->stripAndAccumulateInBoundsConstantOffsets(*DL, Offset);
276 
277     // We want to shuffle the result down from a high element of a vector, so
278     // the offset must be positive.
279     if (Offset.isNegative())
280       return false;
281 
282     // The offset must be a multiple of the scalar element to shuffle cleanly
283     // in the element's size.
284     uint64_t ScalarSizeInBytes = ScalarSize / 8;
285     if (Offset.urem(ScalarSizeInBytes) != 0)
286       return false;
287 
288     // If we load MinVecNumElts, will our target element still be loaded?
289     OffsetEltIndex = Offset.udiv(ScalarSizeInBytes).getZExtValue();
290     if (OffsetEltIndex >= MinVecNumElts)
291       return false;
292 
293     if (!isSafeToLoadUnconditionally(SrcPtr, MinVecTy, Align(1), *DL, Load, &AC,
294                                      &DT))
295       return false;
296 
297     // Update alignment with offset value. Note that the offset could be negated
298     // to more accurately represent "(new) SrcPtr - Offset = (old) SrcPtr", but
299     // negation does not change the result of the alignment calculation.
300     Alignment = commonAlignment(Alignment, Offset.getZExtValue());
301   }
302 
303   // Original pattern: insertelt undef, load [free casts of] PtrOp, 0
304   // Use the greater of the alignment on the load or its source pointer.
305   Alignment = std::max(SrcPtr->getPointerAlignment(*DL), Alignment);
306   Type *LoadTy = Load->getType();
307   unsigned AS = Load->getPointerAddressSpace();
308   InstructionCost OldCost =
309       TTI.getMemoryOpCost(Instruction::Load, LoadTy, Alignment, AS, CostKind);
310   APInt DemandedElts = APInt::getOneBitSet(MinVecNumElts, 0);
311   OldCost +=
312       TTI.getScalarizationOverhead(MinVecTy, DemandedElts,
313                                    /* Insert */ true, HasExtract, CostKind);
314 
315   // New pattern: load VecPtr
316   InstructionCost NewCost =
317       TTI.getMemoryOpCost(Instruction::Load, MinVecTy, Alignment, AS, CostKind);
318   // Optionally, we are shuffling the loaded vector element(s) into place.
319   // For the mask set everything but element 0 to undef to prevent poison from
320   // propagating from the extra loaded memory. This will also optionally
321   // shrink/grow the vector from the loaded size to the output size.
322   // We assume this operation has no cost in codegen if there was no offset.
323   // Note that we could use freeze to avoid poison problems, but then we might
324   // still need a shuffle to change the vector size.
325   auto *Ty = cast<FixedVectorType>(I.getType());
326   unsigned OutputNumElts = Ty->getNumElements();
327   SmallVector<int, 16> Mask(OutputNumElts, PoisonMaskElem);
328   assert(OffsetEltIndex < MinVecNumElts && "Address offset too big");
329   Mask[0] = OffsetEltIndex;
330   if (OffsetEltIndex)
331     NewCost += TTI.getShuffleCost(TTI::SK_PermuteSingleSrc, Ty, MinVecTy, Mask,
332                                   CostKind);
333 
334   // We can aggressively convert to the vector form because the backend can
335   // invert this transform if it does not result in a performance win.
336   if (OldCost < NewCost || !NewCost.isValid())
337     return false;
338 
339   // It is safe and potentially profitable to load a vector directly:
340   // inselt undef, load Scalar, 0 --> load VecPtr
341   IRBuilder<> Builder(Load);
342   Value *CastedPtr =
343       Builder.CreatePointerBitCastOrAddrSpaceCast(SrcPtr, Builder.getPtrTy(AS));
344   Value *VecLd = Builder.CreateAlignedLoad(MinVecTy, CastedPtr, Alignment);
345   VecLd = Builder.CreateShuffleVector(VecLd, Mask);
346 
347   replaceValue(I, *VecLd);
348   ++NumVecLoad;
349   return true;
350 }
