352 /// If we are loading a vector and then inserting it into a larger vector with
353 /// undefined elements, try to load the larger vector and eliminate the insert.
354 /// This removes a shuffle in IR and may allow combining of other loaded values.
355 bool VectorCombine::widenSubvectorLoad(Instruction &I) {
356   // Match subvector insert of fixed vector.
357   auto *Shuf = cast<ShuffleVectorInst>(&I);
358   if (!Shuf->isIdentityWithPadding())
359     return false;
360 
361   // Allow a non-canonical shuffle mask that is choosing elements from op1.
362   unsigned NumOpElts =
363       cast<FixedVectorType>(Shuf->getOperand(0)->getType())->getNumElements();
364   unsigned OpIndex = any_of(Shuf->getShuffleMask(), [&NumOpElts](int M) {
365     return M >= (int)(NumOpElts);
366   });
367 
368   auto *Load = dyn_cast<LoadInst>(Shuf->getOperand(OpIndex));
369   if (!canWidenLoad(Load, TTI))
370     return false;
371 
372   // We use minimal alignment (maximum flexibility) because we only care about
373   // the dereferenceable region. When calculating cost and creating a new op,
374   // we may use a larger value based on alignment attributes.
375   auto *Ty = cast<FixedVectorType>(I.getType());
376   Value *SrcPtr = Load->getPointerOperand()->stripPointerCasts();
377   assert(isa<PointerType>(SrcPtr->getType()) && "Expected a pointer type");
378   Align Alignment = Load->getAlign();
379   if (!isSafeToLoadUnconditionally(SrcPtr, Ty, Align(1), *DL, Load, &AC, &DT))
380     return false;
381 
382   Alignment = std::max(SrcPtr->getPointerAlignment(*DL), Alignment);
383   Type *LoadTy = Load->getType();
384   unsigned AS = Load->getPointerAddressSpace();
385 
386   // Original pattern: insert_subvector (load PtrOp)
387   // This conservatively assumes that the cost of a subvector insert into an
388   // undef value is 0. We could add that cost if the cost model accurately
389   // reflects the real cost of that operation.
390   InstructionCost OldCost =
391       TTI.getMemoryOpCost(Instruction::Load, LoadTy, Alignment, AS, CostKind);
392 
393   // New pattern: load PtrOp
394   InstructionCost NewCost =
395       TTI.getMemoryOpCost(Instruction::Load, Ty, Alignment, AS, CostKind);
396 
397   // We can aggressively convert to the vector form because the backend can
398   // invert this transform if it does not result in a performance win.
399   if (OldCost < NewCost || !NewCost.isValid())
400     return false;
401 
402   IRBuilder<> Builder(Load);
403   Value *CastedPtr =
404       Builder.CreatePointerBitCastOrAddrSpaceCast(SrcPtr, Builder.getPtrTy(AS));
405   Value *VecLd = Builder.CreateAlignedLoad(Ty, CastedPtr, Alignment);
406   replaceValue(I, *VecLd);
407   ++NumVecLoad;
408   return true;
409 }
