411 /// Determine which, if any, of the inputs should be replaced by a shuffle
412 /// followed by extract from a different index.
413 ExtractElementInst *VectorCombine::getShuffleExtract(
414     ExtractElementInst *Ext0, ExtractElementInst *Ext1,
415     unsigned PreferredExtractIndex = InvalidIndex) const {
416   auto *Index0C = dyn_cast<ConstantInt>(Ext0->getIndexOperand());
417   auto *Index1C = dyn_cast<ConstantInt>(Ext1->getIndexOperand());
418   assert(Index0C && Index1C && "Expected constant extract indexes");
419 
420   unsigned Index0 = Index0C->getZExtValue();
421   unsigned Index1 = Index1C->getZExtValue();
422 
423   // If the extract indexes are identical, no shuffle is needed.
424   if (Index0 == Index1)
425     return nullptr;
426 
427   Type *VecTy = Ext0->getVectorOperand()->getType();
428   assert(VecTy == Ext1->getVectorOperand()->getType() && "Need matching types");
429   InstructionCost Cost0 =
430       TTI.getVectorInstrCost(*Ext0, VecTy, CostKind, Index0);
431   InstructionCost Cost1 =
432       TTI.getVectorInstrCost(*Ext1, VecTy, CostKind, Index1);
433 
434   // If both costs are invalid no shuffle is needed
435   if (!Cost0.isValid() && !Cost1.isValid())
436     return nullptr;
437 
438   // We are extracting from 2 different indexes, so one operand must be shuffled
439   // before performing a vector operation and/or extract. The more expensive
440   // extract will be replaced by a shuffle.
441   if (Cost0 > Cost1)
442     return Ext0;
443   if (Cost1 > Cost0)
444     return Ext1;
445 
446   // If the costs are equal and there is a preferred extract index, shuffle the
447   // opposite operand.
448   if (PreferredExtractIndex == Index0)
449     return Ext1;
450   if (PreferredExtractIndex == Index1)
451     return Ext0;
452 
453   // Otherwise, replace the extract with the higher index.
454   return Index0 > Index1 ? Ext0 : Ext1;
455 }
