5073 /// Returns the index of the element within the given load \p L that corresponds
5074 /// to the \p TargetBit offset. Returns -1 if the data is out of the load's
5075 /// range or if it is not aligned with the element boundaries.
5076 static int getIdxInLoad(LoadInst *L, int64_t TargetBit, unsigned ElementSize,
5077                         const DataLayout &DL) {
5078   if (!L)
5079     return -1;
5080 
5081   int64_t LOffBytes;
5082   GetPointerBaseWithConstantOffset(L->getPointerOperand(), LOffBytes, DL);
5083   int64_t LOffBits = LOffBytes * 8; // Convert to bit-level offset.
5084   uint64_t LSizeBits = DL.getTypeStoreSizeInBits(L->getType());
5085   // Check if the target range is fully contained within the load.
5086   if (TargetBit >= LOffBits &&
5087       (TargetBit + ElementSize) <= (LOffBits + (int64_t)LSizeBits)) {
5088     // The target must start at a valid element boundary to be addressable.
5089     if ((TargetBit - LOffBits) % ElementSize == 0)
5090       return (int)((TargetBit - LOffBits) / ElementSize);
5091   }
5092 
5093   return -1;
5094 }
