5101                                       Value *Op0 = nullptr,
5102                                       Value *Op1 = nullptr,
5103                                       const Instruction *I = nullptr) {
5104   unsigned SrcNum = cast<FixedVectorType>(SrcTy)->getNumElements();
5105   TargetTransformInfo::ShuffleKind Kind = TargetTransformInfo::SK_PermuteTwoSrc;
