5146 /// Consolidate a tree of shuffles fed by fragmented narrow loads from adjacent
5147 /// memory addresses into a structured two-level shuffle hierarchy.
5148 ///
5149 /// This transformation flattens deep "incremental build" shuffle trees by
5150 /// grouping lane origins by their base pointers. It constructs intermediate
5151 /// buffers for each base, where each lane is pre-positioned to match its
5152 /// final destination in the result vector.
5153 ///
5154 /// Example Source (Incremental Build):
5155 ///   %0 = load <2 x d>, ptr %x      ; Mem: [x+0, x+8]
5156 ///   %1 = load <2 x d>, ptr %y      ; Mem: [y+0, y+8]
5157 ///   %v1 = shuffle %0, %1, <1, 2>   ; Reg: [x[1], y[0]] (Lanes 0, 1)
5158 ///   %2 = load <2 x d>, ptr %x+16   ; Mem: [x+16, x+24]
5159 ///   %v2 = shuffle %v1, %2, <0, 1, 3> ; Reg: [x[1], y[0], x[3]] (Lanes 0, 1, 2)
5160 ///   %3 = load <2 x d>, ptr %y+16   ; Mem: [y+16, y+24]
5161 ///   %res = shuffle %v2, %3, <0, 1, 2, 4> ; Result: [x[1], y[0], x[3], y[2]]
5162 ///
5163 /// Memory View of Final Result:
5164 ///   Lane 0: BaseX + 8B  (x[1])
5165 ///   Lane 1: BaseY + 0B  (y[0])
5166 ///   Lane 2: BaseX + 24B (x[3])
5167 ///   Lane 3: BaseY + 16B (y[2])
5168 ///
5169 /// Transformed Structure (Mapping-Sync Buffers):
5170 ///   ; Each buffer lane i matches result lane i if the base pointer matches.
5171 ///   %buf_x = shuffle %0, %2, <1, u, 3, u>    ; Reg: [x[1], undef, x[3], undef]
5172 ///   %buf_y = shuffle %1, %3, <u, 0, u, 2>    ; Reg: [undef, y[0], undef, y[2]]
5173 ///   %res   = shuffle %buf_x, %buf_y, <0, 5, 2, 7> ; Final Selection
5174 ///
5175 /// This avoids unsafe speculative load widening by utilizing existing narrow
5176 /// loads while significantly reducing shuffle latency and tree depth.
5177 bool VectorCombine::foldShuffleOfFragmentedLoads(Instruction &I) {
5178   auto *VT = dyn_cast<FixedVectorType>(I.getType());
5179   if (!VT || I.use_empty())
5180     return false;
5181 
5182   unsigned NumElts = VT->getNumElements();
5183   Type *EltTy = VT->getElementType();
5184   unsigned ElementSize = DL->getTypeSizeInBits(EltTy);
5185   SmallVector<LaneOrigin, 4> Origins(NumElts);
5186   SmallVector<Value *, 2> Bases;
5187   SmallPtrSet<Instruction *, 8> VisitedShuffles;
5188   for (unsigned Lane = 0; Lane < NumElts; ++Lane) {
5189     Value *V = &I;
5190     unsigned CurrLane = Lane;
5191     while (auto *SVI = dyn_cast<ShuffleVectorInst>(V)) {
5192       // Collect unique shuffle instructions in the original tree to accurately
5193       // estimate the original cost without double-counting.
5194       VisitedShuffles.insert(SVI);
5195       int M = SVI->getMaskValue(CurrLane);
5196       if (M < 0) {
5197         V = nullptr;
5198         break;
5199       }
5200       unsigned NumOp0 = cast<FixedVectorType>(SVI->getOperand(0)->getType())
5201                             ->getNumElements();
5202       if ((unsigned)M < NumOp0) {
5203         V = SVI->getOperand(0);
5204         CurrLane = M;
5205       } else {
5206         V = SVI->getOperand(1);
5207         CurrLane = M - NumOp0;
5208       }
5209     }
5210     if (!V)
5211       continue;
5212 
5213     auto *LI = dyn_cast<LoadInst>(V);
5214     if (!LI || LI->getType()->getScalarType() != EltTy)
5215       return false;
5216 
5217     int64_t ConstOff = 0;
5218     Value *Base = GetPointerBaseWithConstantOffset(LI->getPointerOperand(),
5219                                                    ConstOff, *DL);
5220     if (!Base)
5221       return false;
5222 
5223     int64_t OffsetInBits = (ConstOff * 8) + (int64_t)(CurrLane * ElementSize);
5224     Origins[Lane] = {LI, OffsetInBits, Base, (unsigned)CurrLane};
5225     if (!is_contained(Bases, Base)) {
5226       if (Bases.size() >= 2)
5227         return false;
5228       Bases.push_back(Base);
5229     }
5230   }
5231 
5232   auto CanWidenSafety = [&](LoadInst *L, FixedVectorType *TargetTy, int BIdx) {
5233     if (cast<FixedVectorType>(L->getType()) == TargetTy)
5234       return true;
5235 
5236     // Determinism Guard: Abort if any lane associated with this base is
5237     // indeterminate (poison/undef). This ensures that we do not widen
5238     // memory accesses for uncertain references.
5239     for (unsigned I = 0; I < NumElts; ++I)
5240       if (Origins[I].BasePtr == Bases[BIdx] && !Origins[I].LI)
5241         return false;
5242 
5243     // Verify that all elements actually utilized by the final shuffle result
5244     // are deterministic. Widening is disallowed if the root shuffle mask
5245     // references a lane that originates from a poison value in the source tree.
5246     auto *SVI = cast<ShuffleVectorInst>(&I);
5247     for (unsigned I = 0; I < NumElts; ++I) {
5248       int M = SVI->getMaskValue(I);
5249       if (M < 0)
5250         continue;
5251 
5252       // Determine if the mask index points to the current base being processed.
5253       unsigned TargetBaseIdx = (unsigned)M < NumElts ? 0 : 1;
5254       if (TargetBaseIdx == (unsigned)BIdx)
5255         if (!Origins[I].LI)
5256           return false;
5257     }
5258 
5259     return canWidenLoad(L, TTI);
5260   };
5261 
5262   SmallVector<ShufflePlan, 2> BasePlans;
5263   for (unsigned BIdx = 0; BIdx < Bases.size(); ++BIdx) {
5264     Value *Base = Bases[BIdx];
5265     // Collect required offsets and candidate loads for this base.
5266     SmallVector<LoadInst *, 8> Candidates;
5267     SmallVector<int64_t, 8> NeededOffsets;
5268     for (const auto &O : Origins) {
5269       if (O.BasePtr == Base && O.LI) {
5270         if (!is_contained(Candidates, O.LI))
5271           Candidates.push_back(O.LI);
5272         if (!is_contained(NeededOffsets, O.OffsetInBits))
5273           NeededOffsets.push_back(O.OffsetInBits);
5274       }
5275     }
5276 
5277     // Find a pair of loads that collectively cover all required lanes.
5278     LoadInst *LI_A = nullptr, *LI_B = nullptr;
5279     for (unsigned I = 0; I < Candidates.size(); ++I) {
5280       for (unsigned J = I; J < Candidates.size(); ++J) {
5281         auto *L1 = Candidates[I], *L2 = Candidates[J];
5282         auto IsCovered = [&](int64_t Off) {
5283           return getIdxInLoad(L1, Off, ElementSize, *DL) != -1 ||
5284                  getIdxInLoad(L2, Off, ElementSize, *DL) != -1;
5285         };
5286         if (all_of(NeededOffsets, IsCovered)) {
5287           LI_A = L1;
5288           LI_B = L2;
5289           break;
5290         }
5291       }
5292       if (LI_A)
5293         break;
5294     }
5295     if (!LI_A)
5296       return false;
5297 
5298     ShufflePlan Plan;
5299     Plan.A = LI_A;
5300     Plan.B = (LI_B != LI_A) ? LI_B : nullptr;
5301     // Check if the types of the chosen loads match. If not, determine if we
5302     // can safely widen the narrower load to the larger target type to
5303     // consolidate the memory layout.
5304     auto *TyA = cast<FixedVectorType>(Plan.A->getType());
5305     if (Plan.B) {
5306       auto *TyB = cast<FixedVectorType>(Plan.B->getType());
5307       if (TyA != TyB) {
5308         auto *TargetTy =
5309             (DL->getTypeSizeInBits(TyA) > DL->getTypeSizeInBits(TyB)) ? TyA
5310                                                                       : TyB;
5311         if (!CanWidenSafety(Plan.A, TargetTy, BIdx) ||
5312             !CanWidenSafety(Plan.B, TargetTy, BIdx))
5313           return false;
5314         Plan.NeedsPromotion = true;
5315         Plan.PromotionTargetTy = TargetTy;
5316       }
5317     }
